    spore_floater = {
        name = "Spore Floater", threat_cost = 3, hp = 12, dps = 2.6, range = 6.0, speed = 1.2,
        color = C.teal, head = C.teal,
        sprite = true, texture = Hive.tex.floater, flies = true,
        parts = 2, scale = 1.05,
        body_pos = { 0.0, 1.05, 0.0 }, body_scale = { 1.02, 1.10, 0.05 },
        head_scale = { 0.001, 0.001, 0.001 },
        hold_range = 6.0, anchor_hold = true, needs_los = true, los_reposition_seconds = 2.0,
