    behemoth = {
        name = "Behemoth", threat_cost = 6, hp = 80, dps = 9.5, range = 1.05, speed = 0.95,
        color = C.behemoth, head = C.behemoth,
        sprite = true, texture = Hive.tex.behemoth,
        parts = 2, scale = 1.72,
