    stinger = {
        name = "Stinger", threat_cost = 2, hp = 8, dps = 3.2, range = 0.55, speed = 3.4,
        color = C.stinger, head = C.stinger,
        sprite = true, texture = Hive.tex.stinger, flies = true,
        parts = 2, scale = 0.95,
        body_pos = { 0.0, 1.10, 0.0 }, body_scale = { 1.16, 0.92, 0.05 },
